const quotePremium = (items: unknown[]): number => {
  if (items.length === 0) return PROCESSING_FEE_G;
  const runeCount = items.length;
  const base = runeCount === 3 ? 60 : runeCount * 25;
  return Math.ceil(base * 1.1) + PROCESSING_FEE_G;
};

